using System.ComponentModel;using System.Globalization;using System.Text;using System.Text.Json;using BgCommon.Text.Json;namespace BgCommon;/// <summary>/// 提供各种基础类型与对象之间的转换工具类./// </summary>public static class BgConvert{    /// <summary>    /// 通用泛型转换.    /// </summary>    /// <typeparam name="T">目标类型.</typeparam>    /// <param name="input">输入对象.</param>    /// <returns>转换后的目标类型值.</returns>    public static T? To<T>(object? input)    {        // 如果输入为空则返回默认值        if (input == null)        {            return default;        }        // 处理空字符串情况        if (input is string && string.IsNullOrWhiteSpace(input.ToString()))        {            return default;        }        Type targetType = Common.GetType<T>();        string typeName = targetType.Name.ToUpperInvariant();        try        {            // 处理字符串和 Guid 类型            if (typeName == "STRING" || typeName == "GUID")            {                return (T)TypeDescriptor.GetConverter(typeof(T)).ConvertFromInvariantString(input.ToString()!)!;            }            // 处理枚举类型            if (targetType.IsEnum)            {                string enumStringValue = input.SafeString();                if (string.IsNullOrWhiteSpace(enumStringValue))                {                    if (typeof(T).IsGenericType)                    {                        return default;                    }                    throw new ArgumentNullException(nameof(input));                }                return (T)Enum.Parse(Common.GetType<T>(), enumStringValue, true);            }            // 处理可转换接口类型            if (input is IConvertible)            {                return (T)Convert.ChangeType(input, targetType, CultureInfo.InvariantCulture);            }            // 处理 JsonElement 类型            if (input is JsonElement jsonElement)            {                var jsonRawText = jsonElement.GetRawText();                var serializeOptions = new JsonSerializerOptions { PropertyNameCaseInsensitive = true };                return JsonConvert.ToObject<T>(jsonRawText, serializeOptions);            }            return (T)input;        }        catch        {            return default;        }    }    /// <summary>    /// 转换为32位整型.    /// </summary>    /// <param name="input">输入对象.</param>    /// <returns>转换后的整数，失败返回0.</returns>    public static int ToInt(object input)    {        return ToIntOrNull(input) ?? 0;    }    /// <summary>    /// 转换为32位可空整型.    /// </summary>    /// <param name="input">输入对象.</param>    /// <returns>转换后的整数或 null.</returns>    public static int? ToIntOrNull(object input)    {        // 尝试直接解析        var isParsed = int.TryParse(input.SafeString(), out var intResult);        if (isParsed)        {            return intResult;        }        try        {            // 尝试先转为浮点数再转换            var doubleValue = ToDoubleOrNull(input, 0);            if (doubleValue == null)            {                return null;            }            return Convert.ToInt32(doubleValue);        }        catch        {            return null;        }    }    /// <summary>    /// 转换为64位整型.    /// </summary>    /// <param name="input">输入对象.</param>    /// <returns>转换后的长整数，失败返回0.</returns>    public static long ToLong(object? input)    {        return ToLongOrNull(input) ?? 0;    }    /// <summary>    /// 转换为64位可空整型.    /// </summary>    /// <param name="input">输入对象.</param>    /// <returns>转换后的长整数或 null.</returns>    public static long? ToLongOrNull(object? input)    {        // 尝试直接解析        var isParsed = long.TryParse(input.SafeString(), out var longResult);        if (isParsed)        {            return longResult;        }        try        {            // 尝试先转为高精度浮点数再转换            var decimalValue = ToDecimalOrNull(input, 0);            if (decimalValue == null)            {                return null;            }            return Convert.ToInt64(decimalValue);        }        catch        {            return null;        }    }    /// <summary>    /// 转换为32位浮点型,并按指定小数位舍入.    /// </summary>    /// <param name="input">输入对象.</param>    /// <param name="digits">保留的小数位数.</param>    /// <returns>转换后的浮点数，失败返回0.</returns>    public static float ToFloat(object input, int? digits = null)    {        return ToFloatOrNull(input, digits) ?? 0;    }    /// <summary>    /// 转换为32位可空浮点型,并按指定小数位舍入.    /// </summary>    /// <param name="input">输入对象.</param>    /// <param name="digits">保留的小数位数.</param>    /// <returns>转换后的浮点数或 null.</returns>    public static float? ToFloatOrNull(object input, int? digits = null)    {        // 尝试解析浮点数        var isParsed = float.TryParse(input.SafeString(), out var floatResult);        if (!isParsed)        {            return null;        }        // 处理舍入逻辑        if (digits == null)        {            return floatResult;        }        return (float)Math.Round(floatResult, digits.Value);    }    /// <summary>    /// 转换为64位浮点型,并按指定小数位舍入.    /// </summary>    /// <param name="input">输入对象.</param>    /// <param name="digits">保留的小数位数.</param>    /// <returns>转换后的双精度浮点数，失败返回0.</returns>    public static double ToDouble(object input, int? digits = null)    {        return ToDoubleOrNull(input, digits) ?? 0;    }    /// <summary>    /// 转换为64位可空浮点型,并按指定小数位舍入.    /// </summary>    /// <param name="input">输入对象.</param>    /// <param name="digits">保留的小数位数.</param>    /// <returns>转换后的双精度浮点数或 null.</returns>    public static double? ToDoubleOrNull(object input, int? digits = null)    {        // 尝试解析双精度浮点数        var isParsed = double.TryParse(input.SafeString(), out var doubleResult);        if (!isParsed)        {            return null;        }        // 处理舍入逻辑        if (digits == null)        {            return doubleResult;        }        return Math.Round(doubleResult, digits.Value);    }    /// <summary>    /// 转换为128位浮点型,并按指定小数位舍入.    /// </summary>    /// <param name="input">输入对象.</param>    /// <param name="digits">保留的小数位数.</param>    /// <returns>转换后的高精度浮点数，失败返回0.</returns>    public static decimal ToDecimal(object input, int? digits = null)    {        return ToDecimalOrNull(input, digits) ?? 0;    }    /// <summary>    /// 转换为128位可空浮点型,并按指定小数位舍入.    /// </summary>    /// <param name="input">输入对象.</param>    /// <param name="digits">保留的小数位数.</param>    /// <returns>转换后的高精度浮点数或 null.</returns>    public static decimal? ToDecimalOrNull(object? input, int? digits = null)    {        // 尝试解析高精度浮点数        var isParsed = decimal.TryParse(input.SafeString(), out var decimalResult);        if (!isParsed)        {            return null;        }        // 处理舍入逻辑        if (digits == null)        {            return decimalResult;        }        return Math.Round(decimalResult, digits.Value);    }    /// <summary>    /// 转换为布尔值.    /// </summary>    /// <param name="input">输入对象.</param>    /// <returns>转换后的布尔值，失败返回 false.</returns>    public static bool ToBool(object input)    {        return ToBoolOrNull(input) ?? false;    }    /// <summary>    /// 转换为可空布尔值.    /// </summary>    /// <param name="input">输入对象.</param>    /// <returns>转换后的布尔值或 null.</returns>    public static bool? ToBoolOrNull(object input)    {        var stringValue = input.SafeString();        bool boolValue = false;        return stringValue switch        {            "1" => true,            "0" => false,            _ => bool.TryParse(stringValue, out boolValue) ? boolValue : null        };    }    /// <summary>    /// 转换为日期.    /// </summary>    /// <param name="input">输入对象.</param>    /// <returns>转换后的日期值，失败返回 MinValue.</returns>    public static DateTime ToDateTime(object? input)    {        return ToDateTimeOrNull(input) ?? DateTime.MinValue;    }    /// <summary>    /// 转换为可空日期.    /// </summary>    /// <param name="input">输入对象.</param>    /// <returns>转换后的日期值或 null.</returns>    public static DateTime? ToDateTimeOrNull(object? input)    {        // 尝试解析日期字符串        var isParsed = DateTime.TryParse(input.SafeString(), out DateTime dateTimeResult);        if (isParsed == false)        {            return null;        }        return dateTimeResult;    }    /// <summary>    /// 转换为Guid.    /// </summary>    /// <param name="input">输入对象.</param>    /// <returns>转换后的 Guid，失败返回 Empty.</returns>    public static Guid ToGuid(object input)    {        return ToGuidOrNull(input) ?? Guid.Empty;    }    /// <summary>    /// 转换为可空Guid.    /// </summary>    /// <param name="input">输入对象.</param>    /// <returns>转换后的 Guid 或 null.</returns>    public static Guid? ToGuidOrNull(object input)    {        if (input == null)        {            return null;        }        // 支持从字节数组构造        if (input.GetType() == typeof(byte[]))        {            return new Guid((byte[])input);        }        return Guid.TryParse(input.SafeString(), out Guid guidResult) ? guidResult : null;    }    /// <summary>    /// 转换为Guid集合.    /// </summary>    /// <param name="input">以逗号分隔的Guid集合字符串.</param>    /// <returns>Guid 列表.</returns>    public static List<Guid> ToGuidList(string input)    {        return ToList<Guid>(input);    }    /// <summary>    /// 转换为字节数组.    /// </summary>    /// <param name="input">输入字符串.</param>    /// <returns>UTF8 编码的字节数组.</returns>    public static byte[] ToBytes(string input)    {        return ToBytes(input, Encoding.UTF8);    }    /// <summary>    /// 转换为字节数组.    /// </summary>    /// <param name="input">输入字符串.</param>    /// <param name="encoding">字符编码.</param>    /// <returns>指定编码的字节数组.</returns>    public static byte[] ToBytes(string input, Encoding encoding)    {        // 如果输入为空则返回空数组        return string.IsNullOrWhiteSpace(input) ? Array.Empty<byte>() : encoding.GetBytes(input);    }    /// <summary>    /// 转换为 base64字符串.    /// </summary>    /// <param name="input">输入字符串.</param>    /// <returns>Base64 编码字符串.</returns>    public static string ToBase64(string input)    {        // 转换逻辑：先转 UTF8 字节再转 Base64        return input.IsEmpty() ? string.Empty : Convert.ToBase64String(Encoding.UTF8.GetBytes(input));    }    /// <summary>    /// 泛型集合转换.    /// </summary>    /// <typeparam name="T">目标元素类型.</typeparam>    /// <param name="input">以逗号分隔的元素集合字符串.</param>    /// <returns>解析后的泛型列表.</returns>    public static List<T> ToList<T>(string input)    {        var resultList = new List<T>();        if (string.IsNullOrWhiteSpace(input))        {            return resultList;        }        // 以逗号分割并排除空项        var stringArray = input.Split(',');        var nonEmptyItems = stringArray.Where(item => !string.IsNullOrWhiteSpace(item))                                       .Select(item => To<T>(item)!)                                       .ToArray();        resultList.AddRange(nonEmptyItems);        return resultList;    }    /// <summary>    /// 对象转换为属性名值对.    /// </summary>    /// <param name="data">数据对象.</param>    /// <returns>属性名字典.</returns>    public static IDictionary<string, object?> ToDictionary(object data)    {        return ToDictionary(data, false);    }    /// <summary>    /// 对象转换为属性名值对.    /// </summary>    /// <param name="data">数据对象.</param>    /// <param name="useDisplayName">是否使用显示名称（Description 或 DisplayName 特性）.</param>    /// <returns>属性名字典.</returns>    public static IDictionary<string, object?> ToDictionary(object data, bool useDisplayName)    {        var dictionaryResult = new Dictionary<string, object?>();        if (data == null)        {            return dictionaryResult;        }        // 如果已经是字典则直接返回        if (data is IEnumerable<KeyValuePair<string, object?>> sourceDictionary)        {            return new Dictionary<string, object?>(sourceDictionary);        }        // 遍历属性描述符进行转换        foreach (PropertyDescriptor property in TypeDescriptor.GetProperties(data))        {            var propertyValue = property.GetValue(data);            dictionaryResult.Add(GetPropertyDescriptorName(property, useDisplayName), propertyValue);        }        return dictionaryResult;    }    /// <summary>    /// 获取属性描述符的展示名称.    /// </summary>    /// <param name="property">属性描述符.</param>    /// <param name="useDisplayName">是否使用显示名称.</param>    /// <returns>属性名称字符串.</returns>    private static string GetPropertyDescriptorName(PropertyDescriptor property, bool useDisplayName)    {        // 如果不使用显示名称则返回属性原生名称        if (useDisplayName == false)        {            return property.Name;        }        // 优先获取 Description 特性内容        if (string.IsNullOrEmpty(property.Description) == false)        {            return property.Description;        }        // 其次获取 DisplayName 特性内容        if (string.IsNullOrEmpty(property.DisplayName) == false)        {            return property.DisplayName;        }        return property.Name;    }}